import { precompileTemplate } from "@ember/template-compilation";
export default precompileTemplate("{{#each this.versions as |version|~}}\n  {{#if (lf-or @renderWhenFalse version.value)~}}\n    <LiquidChild\n      @version={{version}}\n      @uniqueChildId={{version.uniqueChildId}}\n      @liquidChildDidRender={{this.childDidRender}}\n      class={{@class}}\n    >\n      {{~yield version.value~}}\n    </LiquidChild>\n  {{~/if}}\n{{~/each~}}\n<div class=\"liquid-versions\"\n  {{this.appendVersion}}\n  {{this.appendVersion @value @use @rules @matchContext @versionEquality @renderWhenFalse @class @notify}}\n></div>")